'use server';

import { initializeAdminApp } from '@/firebase/admin';
import { getFirestore } from 'firebase-admin/firestore';
import { getAuth } from 'firebase-admin/auth';
import { headers } from 'next/headers';
import type { QuoteRequestWithId } from '@/lib/types';
import { revalidatePath } from 'next/cache';

/**
 * A secure server action to get all quote requests.
 * It uses the Admin SDK to bypass client-side security rules.
 */
export async function getAdminQuoteRequests(): Promise<{ success: true; data: QuoteRequestWithId[] } | { success: false; error: string }> {
  try {
    const adminApp = initializeAdminApp();
    const adminAuth = getAuth(adminApp);
    const adminFirestore = getFirestore(adminApp);
    
    // 1. Verify the calling user is an admin
    const idToken = headers().get('Authorization')?.split('Bearer ')[1];
    if (!idToken) {
        throw new Error('Authentication token not found.');
    }
    
    const decodedToken = await adminAuth.verifyIdToken(idToken);
    if (decodedToken.admin !== true) {
        return { success: false, error: 'Access Denied: User is not an admin.' };
    }

    // 2. Fetch all quote requests using the Admin SDK
    const quoteRequestsSnapshot = await adminFirestore.collectionGroup('quoteRequests').get();
    
    const quoteRequests = quoteRequestsSnapshot.docs.map(doc => {
      const data = doc.data();
      // Firestore Timestamps need to be converted to serializable format (ISO string)
      const submittedDate = data.submittedDate?.toDate ? data.submittedDate.toDate().toISOString() : data.submittedDate;
      const rentalStartDate = data.rentalStartDate?.toDate ? data.rentalStartDate.toDate().toISOString() : data.rentalStartDate;
      const rentalEndDate = data.rentalEndDate?.toDate ? data.rentalEndDate.toDate().toISOString() : data.rentalEndDate;

      return {
        id: doc.id,
        ...data,
        submittedDate,
        rentalStartDate,
        rentalEndDate,
      } as QuoteRequestWithId;
    });

    return { success: true, data: quoteRequests };

  } catch (error: any) {
    console.error('Error fetching admin quote requests:', error);
    return { success: false, error: error.message || 'An unknown error occurred.' };
  }
}

/**
 * A secure server action to update the status of a quote.
 */
export async function updateQuoteStatus(
    { customerId, quoteId, status }: { customerId: string, quoteId: string, status: QuoteRequestWithId['status'] }
): Promise<{ success: true } | { success: false; error: string }> {
     try {
        const adminApp = initializeAdminApp();
        const adminAuth = getAuth(adminApp);
        const adminFirestore = getFirestore(adminApp);
        
        // 1. Verify the calling user is an admin
        const idToken = headers().get('Authorization')?.split('Bearer ')[1];
        if (!idToken) {
            throw new Error('Authentication token not found.');
        }
    
        const decodedToken = await adminAuth.verifyIdToken(idToken);
        if (decodedToken.admin !== true) {
            return { success: false, error: 'Access Denied: User is not an admin.' };
        }

        // 2. Update the document using the Admin SDK
        const docRef = adminFirestore.collection('customers').doc(customerId).collection('quoteRequests').doc(quoteId);
        await docRef.update({ status: status });

        // 3. Revalidate the path to ensure the UI updates
        revalidatePath('/admin');
        revalidatePath('/tracking');
        
        return { success: true };

     } catch (error: any) {
        console.error(`Error updating quote status for ${quoteId}:`, error);
        return { success: false, error: error.message || 'An unknown error occurred.' };
     }
}
