import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion"
import { Button } from '@/components/ui/button';
import { MoreHorizontal, CheckCircle, XCircle, Clock, Loader2, User, Calendar, Hash, AlertTriangle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAdmin, useFirebase } from '@/firebase';
import type { QuoteRequestWithId } from '@/lib/types';
import { getAdminQuoteRequests, updateQuoteStatus } from './actions';

const statusStyles: { [key: string]: string } = {
  Approved: 'bg-green-100 text-green-800 border-green-200 dark:bg-green-900/50 dark:text-green-300 dark:border-green-800',
  'In Review': 'bg-yellow-100 text-yellow-800 border-yellow-200 dark:bg-yellow-900/50 dark:text-yellow-300 dark:border-yellow-800',
  Pending: 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/50 dark:text-blue-300 dark:border-blue-800',
  Rejected: 'bg-red-100 text-red-800 border-red-200 dark:bg-red-900/50 dark:text-red-300 dark:border-red-800',
  Completed: 'bg-gray-100 text-gray-800 border-gray-200 dark:bg-gray-900/50 dark:text-gray-300 dark:border-gray-800',
};

function QuoteRequestDetails({ request }: { request: QuoteRequestWithId }) {
    const deliveryFee = 20;
    const subtotal = request.items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const total = subtotal + deliveryFee;

    const formatPrice = (price: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(price);

    return (
        <div className="grid md:grid-cols-2 gap-6 p-4 bg-muted/20 dark:bg-muted/50 rounded-b-lg">
            <div className="space-y-4">
                <div className="flex items-center gap-2">
                    <User className="h-4 w-4 text-muted-foreground" />
                    <span className="font-semibold">Customer:</span>
                    <span>{request.customerName} ({request.customerEmail})</span>
                </div>
                <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <span className="font-semibold">Rental Period:</span>
                    <span>{new Date(request.rentalStartDate).toLocaleDateString()} - {new Date(request.rentalEndDate).toLocaleDateString()}</span>
                </div>
                 <div className="flex items-center gap-2">
                    <Hash className="h-4 w-4 text-muted-foreground" />
                    <span className="font-semibold">Request ID:</span>
                    <span className="text-xs font-mono">{request.id}</span>
                </div>
            </div>
            <div className="space-y-4">
                <h4 className="font-semibold">Itemized Quote</h4>
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead>
                            <tr>
                                <th className="text-left py-2 font-normal text-muted-foreground">Item</th>
                                <th className="text-center py-2 font-normal text-muted-foreground">Qty</th>
                                <th className="text-right py-2 font-normal text-muted-foreground">Price</th>
                            </tr>
                        </thead>
                        <tbody>
                            {request.items.map((item, index) => (
                                <tr key={index} className="border-b">
                                    <td className="py-2">{item.name}</td>
                                    <td className="text-center py-2">{item.quantity}</td>
                                    <td className="text-right py-2">{formatPrice(item.price * item.quantity)}</td>
                                </tr>
                            ))}
                        </tbody>
                        <tfoot>
                            <tr>
                                <td colSpan={2} className="py-2 font-semibold text-muted-foreground">Subtotal</td>
                                <td className="text-right py-2 font-semibold">{formatPrice(subtotal)}</td>
                            </tr>
                            <tr>
                                <td colSpan={2} className="py-2 text-muted-foreground">Delivery Fee</td>
                                <td className="text-right py-2">{formatPrice(deliveryFee)}</td>
                            </tr>
                             <tr className="border-t-2 border-primary/20">
                                <td colSpan={2} className="py-2 font-bold text-lg">Estimated Total</td>
                                <td className="text-right py-2 font-bold text-lg">{formatPrice(total)}</td>
                            </tr>
                        </tfoot>
                    </table>
                </div>
            </div>
        </div>
    );
}

function AdminQuoteList() {
    const [requests, setRequests] = useState<QuoteRequestWithId[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            const result = await getAdminQuoteRequests();
            if (result.success) {
                // Ensure submittedDate is a valid string for Date constructor
                const parsedRequests = result.data.map(req => ({
                    ...req,
                    submittedDate: req.submittedDate || new Date().toISOString(),
                }));
                // Sort by most recent first
                parsedRequests.sort((a, b) => new Date(b.submittedDate).getTime() - new Date(a.submittedDate).getTime());
                setRequests(parsedRequests);
            } else {
                setError(result.error);
            }
            setIsLoading(false);
        };
        fetchData();
    }, []);

    const handleStatusChange = async (customerId: string, quoteId: string, status: QuoteRequestWithId['status']) => {
        const result = await updateQuoteStatus({ customerId, quoteId, status });
        if (result.success) {
            setRequests(prevRequests => 
                prevRequests.map(req => 
                    req.id === quoteId ? { ...req, status } : req
                )
            );
        } else {
            // Handle error, e.g., show a toast
            console.error("Failed to update status:", result.error);
        }
    };
    
    if (error) {
        return (
            <Card className="max-w-xl mx-auto bg-destructive/10 border-destructive">
                <CardHeader>
                  <CardTitle className="text-destructive flex items-center gap-2"><AlertTriangle /> Error Fetching Data</CardTitle>
                  <CardDescription className="text-destructive/90">Could not fetch quote requests from the server.</CardDescription>
                </CardHeader>
                <CardContent>
                    <p className="font-semibold">Error Details:</p>
                    <pre className="mt-2 w-full whitespace-pre-wrap rounded-md bg-destructive/10 p-4 text-xs font-mono text-destructive-foreground">
                        {error}
                    </pre>
                </CardContent>
            </Card>
        );
    }

    if (isLoading) {
        return (
            <div className="flex justify-center items-center h-48">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
              <p className="ml-4 text-muted-foreground">Loading requests...</p>
            </div>
        );
    }
    
    return requests && requests.length > 0 ? (
        <Accordion type="single" collapsible className="w-full">
            {requests.map((request) => (
                <AccordionItem value={request.id} key={request.id}>
                    <AccordionTrigger className="hover:bg-muted/50 px-4 rounded-lg data-[state=open]:bg-muted/50">
                        <div className="flex items-center gap-4 text-left flex-1">
                            <div className="flex-grow">
                                <p className="font-semibold">{request.projectDescription || 'Quote Request'}</p>
                                <p className="text-sm text-muted-foreground">{request.customerName} - Submitted: {new Date(request.submittedDate).toLocaleDateString()}</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4 ml-auto pl-4">
                            <Badge variant="outline" className={cn('whitespace-nowrap', statusStyles[request.status])}>
                                {request.status}
                            </Badge>
                             <DropdownMenu onOpenChange={(open) => { if(open) { event?.stopPropagation() }}}>
                                <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
                                <Button aria-haspopup="true" size="icon" variant="ghost">
                                    <MoreHorizontal className="h-4 w-4" />
                                    <span className="sr-only">Toggle menu</span>
                                </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end">
                                <DropdownMenuLabel>Actions</DropdownMenuLabel>
                                <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Approved')}>
                                    <CheckCircle className="mr-2 h-4 w-4" />
                                    Approve
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Rejected')}>
                                    <XCircle className="mr-2 h-4 w-4" />
                                    Reject
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'In Review')}>
                                    <Clock className="mr-2 h-4 w-4" />
                                    Mark as In Review
                                </DropdownMenuItem>
                                </DropdownMenuContent>
                            </DropdownMenu>
                        </div>
                    </AccordionTrigger>
                    <AccordionContent>
                        <QuoteRequestDetails request={request} />
                    </AccordionContent>
                </AccordionItem>
            ))}
        </Accordion>
      ) : (
         <div className="text-center py-16">
            <h3 className="text-xl font-semibold">No quote requests found.</h3>
            <p className="text-muted-foreground mt-2">When customers submit new quotes, they will appear here.</p>
        </div>
      );
}

export default function AdminDashboardPage() {
  const { isAdmin, isCheckingAdmin } = useAdmin();

  if (isCheckingAdmin) {
    return (
      <div className="flex justify-center items-center h-48">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
        <p className="ml-4 text-muted-foreground">Verifying admin access...</p>
      </div>
    );
  }

  return (
    <div className="container mx-auto">
      <header className="mb-8">
        <h1 className="text-4xl font-headline font-bold text-foreground">Admin Dashboard</h1>
        <p className="mt-2 text-lg text-muted-foreground">Manage incoming quote requests.</p>
      </header>
      <Card>
        <CardHeader>
          <CardTitle>Incoming Requests</CardTitle>
          <CardDescription>
            Review and manage all customer quote requests.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isAdmin ? (
            <AdminQuoteList />
          ) : (
            <Card className="max-w-lg mx-auto" variant="outline">
                <CardHeader className="text-center">
                <CardTitle>Access Denied</CardTitle>
                <CardDescription>You do not have permission to view this page. This area is for administrators only.</CardDescription>
                </CardHeader>
            </Card>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
